      final long targetNS = lastNS = lastNS + ((long) (bytes * nsPerByte));
      final long startNS;
      long curNS = startNS = System.nanoTime();
      if (lastNS < curNS) {
        lastNS = curNS;
      }

      // While loop because Thread.sleep doesn't always sleep
      // enough:
      while(true) {
        final long pauseNS = targetNS - curNS;
        if (pauseNS > 0) {
          try {
